// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import static org.junit.jupiter.api.Assertions.assertTrue;

import java.nio.file.Path;
import java.time.Duration;
import java.util.ArrayList;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Optional;
import java.util.Random;
import java.util.Set;

import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.junit.jupiter.api.Test;

/**
 * Always-on deterministic differential smoke test: fixed seeds, a bounded pair budget, and the full invariant battery
 * (soundness, witness validity, robustness, determinism, JSON round-trip). Runs in every {@code mvn verify}; the soak
 * variant with configurable budget is {@code FuzzSoakTest}.
 */
class FuzzSmokeTest {
	private static final int CASE_CAP = 48;
	private static final int PAIRS_PER_SEED = 60;
	private static final long[] SEEDS = { 1L, 2L, 3L };

	@Test
	void generatorIsDeterministicAndDiverse() {
		RandomTreeGenerator generator = new RandomTreeGenerator();
		Set<String> shapes = new LinkedHashSet<>();
		for (long seed = 1; seed <= 20; seed++) {
			TupleExpr first = generator.generate(seed);
			TupleExpr second = generator.generate(seed);
			assertTrue(ExactTreeEquality.equal(first, second), "seed " + seed + " is not deterministic");
			shapes.add(first.toString());
		}
		assertTrue(shapes.size() > 10, "generator collapsed to " + shapes.size() + " distinct trees over 20 seeds");
	}

	@Test
	void everyMutatorAppliesSomewhere() {
		RandomTreeGenerator generator = new RandomTreeGenerator();
		List<TupleExpr> trees = new ArrayList<>();
		for (long seed = 1; seed <= 40; seed++) {
			trees.add(generator.generate(seed));
		}
		List<String> neverApplied = new ArrayList<>();
		for (TupleExprMutator mutator : MutatorLibrary.all()) {
			Random rnd = new Random(0xC0FFEE);
			boolean applied = false;
			for (TupleExpr tree : trees) {
				Optional<TupleExpr> mutated = mutator.apply(tree, rnd);
				if (mutated.isPresent()) {
					applied = true;
					break;
				}
			}
			if (!applied) {
				neverApplied.add(mutator.name());
			}
		}
		assertTrue(neverApplied.isEmpty(), "mutators never applicable over 40 seed trees: " + neverApplied);
	}

	@Test
	void randomPairsUpholdAllInvariants() {
		RandomTreePairSource source = new RandomTreePairSource();
		StringBuilder failures = new StringBuilder();
		for (long seed : SEEDS) {
			DifferentialFuzzHarness harness = new DifferentialFuzzHarness(
					FuzzProfile.primary(CASE_CAP),
					FuzzProfile.secondary(CASE_CAP),
					new PairShrinker(),
					new FuzzArtifactWriter(Path.of("target", "equivalence-fuzz"), seed),
					true);
			FuzzRunSummary summary = harness.run(seed, source.pairs(seed, PAIRS_PER_SEED), Duration.ofMinutes(3));
			// Silent truncation would let a regression among the unjudged pairs ship green — the
			// budget only exists as a runaway backstop, so hitting it is itself a failure.
			assertTrue(summary.pairCount() == PAIRS_PER_SEED,
					() -> "time budget truncated the smoke battery: judged " + summary.pairCount()
							+ " of " + PAIRS_PER_SEED + " pairs for seed " + seed);
			if (!summary.violations().isEmpty()) {
				failures.append(summary.report());
			}
		}
		assertTrue(failures.length() == 0,
				() -> "differential invariant violations (artifacts under target/equivalence-fuzz):\n" + failures);
	}
}
